(window.webpackJsonp=window.webpackJsonp||[]).push([[250],{877:function(n,e){n.exports="\x3c!-- \ntitle: 30-JS_ES6\nsort: \n--\x3e \n\n## 变量\n\n```js\n// 不可重复定义 可修改\nlet a = 404;\n// 不可修改\nconst a = 4;\n```\n\n## 箭头函数\n\n> 一个参数可省`()`\n>\n> 一个`return`可省`{}`\n\n```js\nlet show = function (a) {\n    return a * 2;\n}\nlet show = a => a*2;\n\n// 参数扩展\nlet array1 = [1,2,3]\nlet array2 = [5,6,7]\nlet array = [...array1,...array2]\n// [1, 2, 3, 5, 6, 7]\n```\n\n## 解构赋值\n\n```js\nlet [a,b,c] = [1,2,3]\nlet {a,b,c} = {a:1,b:2,c:3}\n```\n\n## 数组\n\n> map: 映射\treduce: 汇总\tfilter: 过滤器\tforeach: 迭代\n\n```js\nlet arr = [1,2,3]\n// map 映射\nlet result = arr.map(item => item%2==0?1:0)\t// [0,1,0]\n// reduce 汇总\nlet result = arr.reduce((tmp,item) => tmp+item)\t// 6\n// 求平均数\nlet result = arr.reduce((tmp,item,index) => index!=arr.length-1?tmp+item:(tmp+item)/arr.length)\t//2\n// filter 过滤器\nlet result = arr.filter(item=>item%2)\t// [1, 3]\n// foreach: 迭代\narr.forEach(item=>alert(item))\narr.forEach((item,index)=>alert(index+':'+item))\n```\n\n"}}]);